content.css:
* { box-sizing: border-box; margin: 0; padding: 0; }
html, body { font-family: -apple-system, "PingFang SC", "Microsoft YaHei", sans-serif; background: #faf7f2; color: #1f2937; height: 100%; }
#dash-root { padding: 16px; min-height: 100vh; }
.dash-loading { color: #6b7280; padding: 32px; text-align: center; }
.dash-header { margin-bottom: 16px; }
.dash-title { font-size: 20px; font-weight: 600; color: #1f2937; }
.dash-sub { font-size: 12px; color: #6b7280; margin-top: 4px; }
.kpi-row { display: grid; grid-template-columns: repeat(4, 1fr); gap: 12px; margin-bottom: 14px; }
.kpi-card { background: #ffffff; padding: 16px 18px; border-radius: 12px; border: 1px solid #e5e7eb; box-shadow: 0 1px 2px rgba(15,23,42,0.04); position: relative; overflow: hidden; }
.kpi-card::before { content: ''; position: absolute; top: 0; left: 0; right: 0; height: 3px; background: linear-gradient(90deg, #d97706 0%, #2563eb 100%); }
.kpi-label { font-size: 11px; color: #6b7280; margin-bottom: 8px; letter-spacing: 0.3px; }
.kpi-value { font-size: 28px; font-weight: 700; color: #111827; line-height: 1.1; font-variant-numeric: tabular-nums; }
.kpi-trend { font-size: 11px; color: #059669; margin-top: 6px; }
.kpi-trend.neutral { color: #6b7280; }
.kpi-trend.down { color: #dc2626; }
.grid-2 { display: grid; grid-template-columns: 1fr 1fr; gap: 12px; margin-bottom: 12px; }
.grid-3 { display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 12px; margin-bottom: 12px; }
.chart-card { background: #ffffff; border-radius: 12px; border: 1px solid #e5e7eb; padding: 14px 16px 10px; box-shadow: 0 1px 2px rgba(15,23,42,0.04); }
.chart-title { font-size: 13px; font-weight: 600; margin-bottom: 8px; color: #1f2937; display: flex; justify-content: space-between; align-items: center; }
.chart-title .tag { font-size: 10px; font-weight: 400; color: #6b7280; padding: 2px 6px; background: #f3f4f6; border-radius: 4px; }
.chart-body { width: 100%; height: 260px; }
.chart-body.h180 { height: 180px; }
.chart-body.h320 { height: 320px; }
table.dash-tbl { width: 100%; border-collapse: collapse; font-size: 12px; }
table.dash-tbl th { text-align: left; padding: 6px 10px; color: #6b7280; font-weight: 500; border-bottom: 1px solid #e5e7eb; font-size: 10px; letter-spacing: 0.3px; text-transform: uppercase; }
table.dash-tbl td { padding: 8px 10px; border-bottom: 1px solid #f3f4f6; color: #374151; }
table.dash-tbl tr:hover td { background: #fafaf7; }
.tag-pri { display: inline-block; padding: 2px 8px; border-radius: 4px; font-size: 10px; font-weight: 600; letter-spacing: 0.3px; }
.tag-pri.P0 { background: #fee2e2; color: #dc2626; }
.tag-pri.P1 { background: #fef3c7; color: #d97706; }
.tag-pri.P2 { background: #dbeafe; color: #2563eb; }
.tag-risk { display: inline-block; padding: 2px 8px; border-radius: 4px; font-size: 10px; }
.tag-risk.高风险 { background: #fee2e2; color: #dc2626; }
.tag-risk.中风险 { background: #fef3c7; color: #d97706; }
.tag-risk.正常 { background: #d1fae5; color: #059669; }
.tag-role { display: inline-block; padding: 2px 8px; border-radius: 4px; font-size: 10px; }
.tag-role.金牌导购 { background: #fef3c7; color: #d97706; }
.tag-role.普通导购 { background: #e5e7eb; color: #4b5563; }
.tag-role.新人导购 { background: #ddd6fe; color: #7c3aed; }
.tag-role.店长 { background: #d1fae5; color: #059669; }

/* ========== 移动端响应式 (BI ?pageRenderType=phoneView) ========== */
@media (max-width: 768px) {
  html, body { height: auto !important; overflow-y: auto !important; }
  #dash-root { padding: 10px; overflow-y: auto; -webkit-overflow-scrolling: touch; } /* iframe-mobile-scroll */
  .dash-header { margin-bottom: 10px; }
  .dash-title { font-size: 16px; }
  .dash-sub { font-size: 11px; }
  .kpi-row, .grid-2, .grid-3 { grid-template-columns: 1fr 1fr !important; gap: 8px !important; margin-bottom: 10px !important; }
  .kpi-card { padding: 10px 12px; border-radius: 8px; }
  .kpi-label { font-size: 10px; margin-bottom: 4px; }
  .kpi-value { font-size: 18px; }
  .kpi-trend { font-size: 10px; }
  .chart-card { padding: 10px 12px 6px; border-radius: 8px; }
  .chart-title { font-size: 12px; margin-bottom: 6px; }
  .chart-title .tag { font-size: 9px; padding: 1px 4px; }
  .chart-body { height: 200px !important; }
  .chart-body.h180 { height: 160px !important; }
  .chart-body.h220 { height: 180px !important; }
  .chart-body.h320 { height: 240px !important; }
  table.dash-tbl { font-size: 11px; }
  table.dash-tbl th { font-size: 9px; padding: 4px 6px; }
  table.dash-tbl td { padding: 5px 6px; }
  .chip-toolbar { padding: 6px 8px; font-size: 10px; gap: 2px; }
  .chip { padding: 3px 8px; font-size: 10px; margin: 0; }
}
@media (max-width: 480px) {
  .kpi-row { grid-template-columns: 1fr 1fr !important; }
  .grid-2 { grid-template-columns: 1fr !important; }
  .kpi-value { font-size: 16px; }
  .chart-body { height: 180px !important; }
  .chart-body.h180 { height: 150px !important; }
  .chart-body.h320 { height: 220px !important; }
}

content.script:
/**
 * 05-活动权益复盘
 * data[0]: 活动明细 (50 个活动 × 13 个指标)
 */

function fmtNum(v){if(v==null||isNaN(v))return"—";v=Number(v);if(Math.abs(v)>=1e8)return(v/1e8).toFixed(2)+" 亿";if(Math.abs(v)>=1e4)return(v/1e4).toFixed(1)+" 万";return Math.round(v).toLocaleString();}
function fmtPct(v){if(v==null||isNaN(v))return"—";return(Number(v)*100).toFixed(1)+"%";}
function getCol(view,name){if(!view)return null;for(var i=0;i<view.length;i++){if(view[i]&&view[i].name===name)return view[i];}return null;}
function sumArr(a){var s=0;if(!a)return 0;for(var i=0;i<a.length;i++){var v=Number(a[i]);if(!isNaN(v))s+=v;}return s;}
function avg(a){var s=0,n=0;if(!a)return 0;for(var i=0;i<a.length;i++){var v=Number(a[i]);if(!isNaN(v)){s+=v;n++;}}return n?s/n:0;}
function esc(v){if(v==null)return"";return String(v).replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;");}

function renderChart(data){
  var root=document.getElementById('dash-root');
  if(!data||!data[0]){root.innerHTML='<div class="dash-loading">No data</div>';return;}

  var v=data[0];
  var ids=(getCol(v,"活动ID")||{}).data||[];
  var names=(getCol(v,"活动名称")||{}).data||[];
  var types=(getCol(v,"活动类型")||{}).data||[];
  var chans=(getCol(v,"活动渠道")||{}).data||[];
  var issue=(getCol(v,"券发放数")||{}).data||[];
  var use=(getCol(v,"券核销数")||{}).data||[];
  var useRate=(getCol(v,"券核销率")||{}).data||[];
  var disc=(getCol(v,"总折扣")||{}).data||[];
  var reach=(getCol(v,"触达人数")||{}).data||[];
  var view=(getCol(v,"查看人数")||{}).data||[];
  var conv=(getCol(v,"转化人数")||{}).data||[];
  var sales=(getCol(v,"拉动销售")||{}).data||[];
  var convRate=(getCol(v,"总体转化率")||{}).data||[];
  var roi=(getCol(v,"券ROI")||{}).data||[];
  var budget=(getCol(v,"预算")||{}).data||[];

  // KPI
  var totalIssue=sumArr(issue);
  var totalUse=sumArr(use);
  var totalSales=sumArr(sales);
  var totalDisc=sumArr(disc);
  var totalBudget=sumArr(budget);
  var avgUseRate=totalIssue?totalUse/totalIssue:0;
  var avgROI=totalDisc?totalSales/totalDisc:0;

  // 按拉动销售排序
  var rows=[];
  for(var i=0;i<ids.length;i++){
    rows.push({id:ids[i],name:names[i],type:types[i],chan:chans[i],issue:Number(issue[i])||0,use:Number(use[i])||0,disc:Number(disc[i])||0,reach:Number(reach[i])||0,conv:Number(conv[i])||0,sales:Number(sales[i])||0,roi:Number(roi[i])||0,useRate:Number(useRate[i])||0});
  }
  rows.sort(function(a,b){return b.sales-a.sales;});
  var top10=rows.slice(0,10);

  // 类型聚合
  var typeMap={};
  rows.forEach(function(r){
    if(!typeMap[r.type])typeMap[r.type]={cnt:0,sales:0,reach:0,conv:0};
    typeMap[r.type].cnt+=1;
    typeMap[r.type].sales+=r.sales;
    typeMap[r.type].reach+=r.reach;
    typeMap[r.type].conv+=r.conv;
  });
  var typeRows=Object.keys(typeMap).map(function(t){return {type:t,cnt:typeMap[t].cnt,sales:typeMap[t].sales,reach:typeMap[t].reach,conv:typeMap[t].conv,convRate:typeMap[t].reach?typeMap[t].conv/typeMap[t].reach:0};});

  // 漏斗
  var totalReach=sumArr(reach);
  var totalView=sumArr(view);
  var totalConv=sumArr(conv);

  root.innerHTML=(
    '<div class="dash-header">'+
      '<div class="dash-title">🎯 活动权益复盘</div>'+
      '<div class="dash-sub">营销视角 · '+rows.length+' 个活动 · ROI / 漏斗 / Top 排行</div>'+
    '</div>'+
    '<div class="kpi-row">'+
      '<div class="kpi-card"><div class="kpi-label">活动总数</div><div class="kpi-value">'+rows.length+'</div><div class="kpi-trend">'+Object.keys(typeMap).length+' 种类型</div></div>'+
      '<div class="kpi-card"><div class="kpi-label">平均券核销率</div><div class="kpi-value">'+fmtPct(avgUseRate)+'</div><div class="kpi-trend">核销 '+fmtNum(totalUse)+' 张</div></div>'+
      '<div class="kpi-card"><div class="kpi-label">活动拉动销售</div><div class="kpi-value">'+fmtNum(totalSales)+'</div><div class="kpi-trend">▲ 私域+券组合效应</div></div>'+
      '<div class="kpi-card"><div class="kpi-label">平均券 ROI</div><div class="kpi-value">'+avgROI.toFixed(1)+'×</div><div class="kpi-trend">每 1 元折扣 → '+avgROI.toFixed(1)+' 元销售</div></div>'+
    '</div>'+
    '<div class="grid-2">'+
      '<div class="chart-card"><div class="chart-title">Top 10 活动·拉动销售 <span class="tag">爆款</span></div><div id="c-top" class="chart-body"></div></div>'+
      '<div class="chart-card"><div class="chart-title">活动类型对比 <span class="tag">销售 + 转化率</span></div><div id="c-type" class="chart-body"></div></div>'+
    '</div>'+
    '<div class="grid-2">'+
      '<div class="chart-card"><div class="chart-title">触达漏斗 (整体) <span class="tag">私域链路</span></div><div id="c-funnel" class="chart-body"></div></div>'+
      '<div class="chart-card"><div class="chart-title">Top 10 活动明细 <span class="tag">含 ROI</span></div><div id="c-tbl" style="height:260px;overflow:auto;">'+
        '<table class="dash-tbl"><thead><tr><th>#</th><th>活动</th><th>类型</th><th>核销率</th><th>转化人数</th><th>销售</th><th>ROI</th></tr></thead><tbody>'+
        top10.map(function(r,i){
          var roiTag=r.roi>=2?'<b style="color:#059669">'+r.roi.toFixed(1)+'×</b>':r.roi>=1?'<b style="color:#d97706">'+r.roi.toFixed(1)+'×</b>':'<span style="color:#dc2626">'+r.roi.toFixed(1)+'×</span>';
          return '<tr><td><b>'+(i+1)+'</b></td><td>'+esc(r.name)+'</td><td>'+esc(r.type)+'</td><td>'+fmtPct(r.useRate)+'</td><td>'+fmtNum(r.conv)+'</td><td><b>'+fmtNum(r.sales)+'</b></td><td>'+roiTag+'</td></tr>';
        }).join('')+
        '</tbody></table></div></div>'+
    '</div>'
  );

  function ch(id){return echarts.init(document.getElementById(id));}
  function baseTooltip(){return {backgroundColor:'#fff',borderColor:'#e5e7eb',textStyle:{color:'#1f2937'},extraCssText:'box-shadow:0 4px 12px rgba(15,23,42,0.08);border-radius:6px;'};}

  // 1. Top 10 活动 横向条
  ch('c-top').setOption({
    backgroundColor:'transparent',
    tooltip:{trigger:'item',...baseTooltip(),formatter:function(p){var r=top10[top10.length-1-p.dataIndex];return p.name+'<br/>类型: '+r.type+'<br/>销售: '+fmtNum(r.sales)+'<br/>ROI: '+r.roi.toFixed(1)+'×';}},
    grid:{left:130,right:50,top:5,bottom:25},
    xAxis:{type:'value',axisLabel:{color:'#6b7280',formatter:function(v){return fmtNum(v);}},splitLine:{lineStyle:{color:'#f3f4f6'}}},
    yAxis:{type:'category',data:top10.map(function(r){return r.name;}).reverse(),axisLabel:{color:'#374151',fontSize:10},axisLine:{lineStyle:{color:'#e5e7eb'}}},
    series:[{type:'bar',data:top10.map(function(r){return r.sales;}).reverse(),itemStyle:{color:function(p){var roi=top10[top10.length-1-p.dataIndex].roi;return roi>=2?'#059669':roi>=1?'#d97706':'#dc2626';},borderRadius:[0,4,4,0]},label:{show:true,position:'right',color:'#374151',formatter:function(p){return fmtNum(p.value);}}}]
  });

  // 2. 活动类型对比 (双轴: 拉动销售柱 + 转化率折线)
  typeRows.sort(function(a,b){return b.sales-a.sales;});
  var TYPE_COLORS={"新品上市":"#dc2626","节日活动":"#f59e0b","会员日":"#d97706","拉新活动":"#2563eb","复购唤醒":"#059669","私域专享":"#a855f7"};
  ch('c-type').setOption({
    backgroundColor:'transparent',
    legend:{data:['拉动销售','总体转化率'],textStyle:{color:'#6b7280'},top:0,right:10},
    tooltip:{trigger:'axis',axisPointer:{type:'shadow'},...baseTooltip(),
      formatter:function(p){var s='<b>'+p[0].axisValueLabel+'</b><br/>';p.forEach(function(x){if(x.value!=null){var v=x.seriesName==='总体转化率'?fmtPct(x.value):fmtNum(x.value)+' 元';s+=x.marker+x.seriesName+': '+v+'<br/>';}});return s;}},
    grid:{left:70,right:70,top:35,bottom:30},
    xAxis:{type:'category',data:typeRows.map(function(r){return r.type;}),axisLabel:{color:'#374151',fontSize:11},axisLine:{lineStyle:{color:'#e5e7eb'}}},
    yAxis:[
      {type:'value',name:'拉动销售',nameTextStyle:{color:'#6b7280',fontSize:10},axisLabel:{color:'#6b7280',formatter:function(v){return fmtNum(v);}},splitLine:{lineStyle:{color:'#f3f4f6'}}},
      {type:'value',name:'转化率',nameTextStyle:{color:'#6b7280',fontSize:10},axisLabel:{color:'#6b7280',formatter:function(v){return fmtPct(v);}}}
    ],
    series:[
      {name:'拉动销售',type:'bar',itemStyle:{color:function(p){return TYPE_COLORS[typeRows[p.dataIndex].type]||'#2563eb';},borderRadius:[4,4,0,0]},data:typeRows.map(function(r){return r.sales;}),label:{show:true,position:'top',color:'#374151',fontSize:10,formatter:function(p){return fmtNum(p.value);}}},
      {name:'总体转化率',type:'line',yAxisIndex:1,lineStyle:{width:2,color:'#0891b2'},itemStyle:{color:'#0891b2'},symbol:'circle',symbolSize:8,data:typeRows.map(function(r){return r.convRate;}),label:{show:true,position:'top',color:'#0891b2',fontSize:10,formatter:function(p){return fmtPct(p.value);}}}
    ]
  });

  // 3. 漏斗
  ch('c-funnel').setOption({
    backgroundColor:'transparent',
    tooltip:{trigger:'item',...baseTooltip(),formatter:function(p){var pct=totalReach?(p.value/totalReach*100).toFixed(1):0;return p.name+'<br/>'+fmtNum(p.value)+' ('+pct+'%)';}},
    series:[{type:'funnel',left:'10%',top:20,bottom:20,width:'80%',min:0,max:totalReach,minSize:'20%',sort:'descending',gap:2,label:{color:'#1f2937',fontSize:12,formatter:function(p){return p.name+'\n'+fmtNum(p.value);}},itemStyle:{borderWidth:0},data:[
      {value:totalReach,name:'触达',itemStyle:{color:'#94a3b8'}},
      {value:totalView,name:'查看',itemStyle:{color:'#fbbf24'}},
      {value:totalConv,name:'转化下单',itemStyle:{color:'#059669'}}
    ]}]
  });
}

new GDPlugin().init(renderChart);
